INSERT INTO `knowledge` VALUES (3, '自您收到商品之日起7日内，如果商品完好、配件齐全且不影响二次销售，您可以在“我的订单”页面点击“申请售后”来办理退换货。食品、贴身衣物等特殊商品，如无质量问题，不支持7天无理由退货，请您谅解。', '2025-07-22 00:43:02.521000', '如何申请退换货？');
INSERT INTO `knowledge` VALUES (4, '通常情况下，您的订单在支付成功后的24-48小时内会完成打包和发货。大型促销活动期间（如618、双十一），订单量较大，发货可能会有短暂延迟，我们会尽力加快处理，感谢您的耐心等待。', '2025-07-22 00:43:12.247000', '订单支付后多久可以发货？');
INSERT INTO `knowledge` VALUES (5, '在您提交订单的结算页面，系统会自动列出您账户中可用的优惠券。您可以手动勾选希望使用的优惠券，订单金额将自动扣减。请注意，部分特价商品或活动商品可能不支持使用优惠券。', '2025-07-22 00:43:21.053000', '如何使用优惠券？');
INSERT INTO `knowledge` VALUES (6, '您可以在提交订单时，在“发票信息”处选择“需要发票”并填写您的发票抬头和税号信息。电子发票会在订单完成后24小时内发送到您的注册邮箱；纸质发票会随商品一同寄出。\n\n', '2025-07-22 00:43:34.015000', '如何开具发票？');
INSERT INTO `knowledge` VALUES (7, '如果您的问题未能解决，可以在对话框中输入“人工客服”或“转人工”，系统将为您转接。我们的人工客服工作时间为每日上午9:00至晚上22:00，非工作时间您也可以留言，我们会在看到后第一时间回复您。', '2025-07-22 00:43:52.241000', '如何联系人工客服？');
INSERT INTO `knowledge` VALUES (8, '我们目前支持多种主流支付方式，包括微信支付、支付宝、银联云闪付以及主流银行的信用卡和借记卡在线支付。所有支付过程均经过加密处理，确保您的资金安全。', '2025-07-22 00:44:03.128000', '支持哪些支付方式？');
INSERT INTO `knowledge` VALUES (9, '如果您忘记了登录密码，可以在登录页面点击“忘记密码”链接。系统会引导您通过注册时使用的手机号码或电子邮箱来重置密码。操作过程中遇到任何问题，都可以随时联系在线客服。', '2025-07-22 00:44:16.266000', '忘记密码了怎么办？');

